import React, { useContext, useState, useEffect } from 'react';
import { AuthContext } from 'context/AuthContext';
import FoodLogger from 'components/dashboard/FoodLogger';
import NutrientPieChart from 'components/dashboard/NutrientPieChart';
import MealSuggestions from 'components/dashboard/MealSuggestions';
import api from 'api';

const Dashboard = () => {
  const { user } = useContext(AuthContext);
  const [dailyData, setDailyData] = useState({
    protein: 0,
    carbs: 0,
    fats: 0,
    calories: 0,
  });
  const [foodLog, setFoodLog] = useState([]);

  const fetchTodaysFood = async () => {
    try {
      const res = await api.get('/food/today');
      setFoodLog(res.data);
      calculateTotals(res.data);
    } catch (err) {
      console.error('Error fetching today\'s food log:', err);
    }
  };

  const calculateTotals = (log) => {
    const totals = log.reduce(
      (acc, item) => {
        acc.protein += item.protein;
        acc.carbs += item.carbs;
        acc.fats += item.fats;
        acc.calories += item.calories;
        return acc;
      },
      { protein: 0, carbs: 0, fats: 0, calories: 0 }
    );
    setDailyData(totals);
  };

  useEffect(() => {
    fetchTodaysFood();
  }, []);

  const handleFoodLogged = (newFoodItem) => {
    const updatedLog = [...foodLog, newFoodItem];
    setFoodLog(updatedLog);
    calculateTotals(updatedLog);
  };

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-3xl font-bold text-gray-800 mb-4">
        Welcome, {user && user.name}!
      </h1>
      <p className="text-gray-600 mb-8">
        Log your meals to track your daily intake and receive personalized insights.
      </p>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Food Logger and Food Log */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-xl font-semibold mb-4 text-gray-700">Log Your Meal</h2>
            <FoodLogger onFoodLogged={handleFoodLogged} />
          </div>
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-xl font-semibold mb-4 text-gray-700">Today's Food Log</h2>
            <div className="space-y-4">
              {foodLog.length > 0 ? (
                foodLog.map((item) => (
                  <div key={item._id} className="p-3 bg-gray-50 rounded-md border border-gray-200">
                    <p className="font-semibold">{item.name}</p>
                    <p className="text-sm text-gray-600">
                      {item.calories.toFixed(0)} kcal | P: {item.protein.toFixed(1)}g | C: {item.carbs.toFixed(1)}g | F: {item.fats.toFixed(1)}g
                    </p>
                  </div>
                ))
              ) : (
                <p className="text-gray-500">No meals logged yet today.</p>
              )}
            </div>
          </div>
        </div>

        {/* Right Column: Nutrients and Suggestions */}
        <div className="space-y-8">
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-xl font-semibold mb-4 text-gray-700">Today's Nutrients</h2>
            <p className="text-2xl font-bold text-center mb-4 text-green-600">
              {dailyData.calories.toFixed(0)} <span className="text-lg text-gray-600">kcal</span>
            </p>
            <NutrientPieChart data={dailyData} />
          </div>
          <div className="bg-white p-6 rounded-lg shadow-md">
            <h2 className="text-xl font-semibold mb-4 text-gray-700">High-Protein Meal Suggestions</h2>
            <MealSuggestions />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
